func Test_SmokeEmptyString(t *testing.T) {
	// Empty string produces empty output
	result, err := htmd.Convert(``, nil)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	var content string
	if result.Content != nil {
		content = string(*result.Content)
	}
	if strings.TrimSpace(string(content)) != `` {
		t.Errorf("equals mismatch: got %v", content)
	}
}

func Test_SmokeSimpleHeading(t *testing.T) {
	// H1 heading converts to ATX markdown
	result, err := htmd.Convert(`<h1>Title</h1>`, nil)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	if result.Content != nil {
	if !strings.Contains(string(*result.Content), `# Title`) {
		t.Errorf("expected to contain %s", `# Title`)
	}
	}
}

func Test_SmokeSimpleParagraph(t *testing.T) {
	// Simple paragraph converts correctly
	result, err := htmd.Convert(`<p>Hello World</p>`, nil)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	var content string
	if result.Content != nil {
		content = string(*result.Content)
	}
	if strings.TrimSpace(string(content)) != `Hello World` {
		t.Errorf("equals mismatch: got %v", content)
	}
	if len(content) == 0 {
		t.Errorf("expected non-empty value")
	}
}
